queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?screenwriters a :Screenwriters .
    ?screenwriters p:name ?name .
    ?screenwriters p:Education ?education_f .
    FILTER(STR(?education_f) = "New York University")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?playwrights a :Playwrights .
    ?playwrights p:name ?name .
    ?playwrights p:Education ?education_f .
    FILTER(STR(?education_f) = "New York University")
    BIND(?name AS ?o0)
  }
}

